'use client';

import { useEffect, useRef } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { motion } from 'framer-motion';
import { ArrowUpRight } from 'lucide-react';
import type { Cooperative } from '../data/mockData';
import { useCooperativeStore } from '../store/useCooperativeStore';

type CooperativeListProps = {
  cooperatives: Cooperative[];
  className?: string;
  compact?: boolean;
};

export default function CooperativeList({
  cooperatives,
  className,
  compact = false,
}: CooperativeListProps) {
  const activeCooperativeId = useCooperativeStore((state) => state.activeCooperativeId);
  const setActiveCooperativeId = useCooperativeStore((state) => state.setActiveCooperativeId);
  const itemRefs = useRef<Record<string, HTMLDivElement | null>>({});

  useEffect(() => {
    if (!activeCooperativeId) return;

    const target = itemRefs.current[activeCooperativeId];
    if (!target) return;

    target.scrollIntoView({
      behavior: 'smooth',
      block: 'center',
    });
  }, [activeCooperativeId]);

  return (
    <aside
      className={`overflow-y-auto rounded-2xl border border-white/40 bg-white/70 p-3 shadow-lg backdrop-blur-md ${
        compact ? 'h-full' : 'h-[60vh] lg:h-[72vh]'
      } ${className ?? ''}`}
    >
      <div className="space-y-3">
        {cooperatives.map((cooperative, index) => {
          const isActive = cooperative.id === activeCooperativeId;

          return (
            <motion.div
              key={cooperative.id}
              ref={(node) => {
                itemRefs.current[cooperative.id] = node;
              }}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.3, delay: index * 0.04 }}
              onClick={() => setActiveCooperativeId(cooperative.id)}
              className={`group cursor-pointer overflow-hidden rounded-2xl border transition ${
                isActive
                  ? 'border-terracotta/70 bg-terracotta/5 shadow-xl ring-2 ring-terracotta/30'
                  : 'border-white/40 bg-white/60 hover:border-palmier/30 hover:shadow-lg'
              }`}
            >
              <div className="relative aspect-[16/10] w-full overflow-hidden">
                <Image
                  src={cooperative.coverImage}
                  alt={cooperative.coverAlt}
                  fill
                  sizes="(max-width: 768px) 100vw, 45vw"
                  className="object-cover transition duration-500 group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/10 to-transparent" />
                <span className="absolute left-3 top-3 rounded-full bg-white/90 px-2.5 py-1 text-[11px] font-medium uppercase tracking-wide text-palmier backdrop-blur-sm">
                  {cooperative.zone} • {cooperative.category}
                </span>
                <div className="absolute bottom-3 left-3 right-3">
                  <h3 className="text-base font-bold text-white drop-shadow-md line-clamp-2">
                    {cooperative.name}
                  </h3>
                </div>
              </div>
              <div className="p-4">
                <p className="mb-2 line-clamp-1 text-xs text-palmier/70">
                  {cooperative.location.address}
                </p>
                <p className="mb-3 line-clamp-2 text-sm text-palmier/85">
                  {cooperative.descriptionShort}
                </p>
                <div className="mb-3 flex flex-wrap gap-1">
                  {cooperative.products.slice(0, 3).map((product) => (
                    <span
                      key={product.id}
                      className="rounded-full bg-palmier/10 px-2 py-0.5 text-[11px] text-palmier/80"
                    >
                      {product.name.split(' ').slice(0, 2).join(' ')}
                    </span>
                  ))}
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-xs font-medium text-palmier/70">
                    {cooperative.products.length} produit
                    {cooperative.products.length > 1 ? 's' : ''}
                  </span>
                  <Link
                    href={`/cooperative/${cooperative.slug}`}
                    className="inline-flex items-center gap-1 text-sm font-medium text-terracotta hover:underline"
                    onClick={(event) => event.stopPropagation()}
                  >
                    Voir profil
                    <ArrowUpRight size={14} />
                  </Link>
                </div>
              </div>
            </motion.div>
          );
        })}
      </div>
    </aside>
  );
}
